 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import useSingleNodeCluster from '@kubevirt-utils/hooks/useSingleNodeCluster';
 6	import { Label } from '@patternfly/react-core';
 7	import { isLiveMigratable, printableVMStatus } from '@virtualmachines/utils';
 8	
 9	import './VMNotMigratableLabel.scss';
10	
11	type VMNotMigratableLabelProps = {
12	  vm: V1VirtualMachine;
13	};
14	
15	const VMNotMigratableLabel: FC<VMNotMigratableLabelProps> = ({ vm }) => {
16	  const { t } = useKubevirtTranslation();
17	  const [isSingleNodeCluster] = useSingleNodeCluster();
18	  const isMigratable = isLiveMigratable(vm, isSingleNodeCluster);
19	  const isRunning = vm?.status?.printableStatus === printableVMStatus.Running;
20	
21	  if (!isRunning || isMigratable) return null;
22	
23	  return (
24	    <Label
25	      className="migratable-label"
26	      color="blue"
27	      isCompact
28	      key="not-migratable"
29	      variant="outline"
30	    >
31	      {t('Not migratable')}
32	    </Label>
33	  );
34	};
35	
36	export default VMNotMigratableLabel;

